class Parent {
    static void f() { System.out.print("fp"); }
    void g() { System.out.print("gp"); }
}
class Child extends Parent {
    static void f() { System.out.print("fc"); }
    void g() { System.out.print("gc"); }
}
public class C {
    public static void main(String args[]) {
        Parent a = new Child();
        a.f();
        a.g();
    }
}

