class Bag {
    private String color;
    private int size;
    public Bag() {
        this.color = "Unknown";
        this.size = 0;
        System.out.println(color + ", " + size);
    }
    public Bag(String color) {
        this.color = color;
        this.size = 0;
        System.out.println(color + ", " + size);
    }
    public Bag(String color, int size) {
        this.color = color;
        this.size = size;
        System.out.println(color + ", " + size);
    }
}
public class Main {
    public static void main(String[] args) {
        Bag bag1 = new Bag();
        Bag bag3 = new Bag("Blue", 15);
    }
}
